FILES['milaan/match/engine.py'] = '"""Tiered deterministic matching engine — the money path. No ML here.\n\nPasses (in order, each consumes matched items):\n  P1 EXACT     : same amount, direction-consistent, unique best name+date score\n  P2 TOLERANCE : bank amount slightly below ledger (gateway fee / short payment)\n  P3 COMBINED  : one bank credit settles 2-3 ledger invoices (same party)\n  P4 SPLIT     : two bank credits settle one ledger invoice (same party)\n\nEvery match records: rule id, score, and a human-readable explanation.\nDuplicate bank lines (same narration+ref+amount) are pre-flagged.\nDeterminism: stable sorts everywhere; same input -> identical output.\n"""\n\nfrom datetime import date\nfrom itertools import combinations\n\nfrom rapidfuzz import fuzz\n\n# ---------------------------------------------------------------- tunables\nDATE_BEFORE = 1        # bank may precede ledger by at most 1 day\nDATE_AFTER = 7         # bank may lag ledger by up to 7 days\nNAME_THRESHOLD = 70    # min fuzzy score to accept a name link\nTOL_PCT = 0.12         # max fee/short-payment delta as fraction of ledger amt\nTOL_ABS = 50.0         # plus small absolute buffer\nGROUP_MAX = 3          # max invoices in a combined settlement\nGROUP_AFTER = 31       # settlement may lag oldest invoice this many days\n\nSTOPWORDS = {"UPI", "IMPS", "NEFT", "RTGS", "CHQ", "DEP", "CR", "DR",\n             "PAYMENT", "ACH", "D", "BILLPAY", "PMT", "REF", "TRF"}\n\n\ndef _vowel_drop(s: str) -> str:\n    return " ".join(w[0] + "".join(c for c in w[1:] if c not in "AEIOU")\n                    if len(w) > 4 else w for w in s.split())\n\n\ndef narration_hint(narration: str) -> str:\n    """Strip mode prefixes, numbers, VPAs -> probable party text."""\n    toks = []\n    for raw in narration.upper().replace("/", "-").split("-"):\n        for t in raw.split():\n            if not t or t in STOPWORDS or "@" in t:\n                continue\n            if sum(c.isdigit() for c in t) > len(t) // 2:\n                continue\n            toks.append(t)\n    return " ".join(toks)\n\n\ndef name_score(narration: str, party: str) -> float:\n    hint = narration_hint(narration)\n    if not hint:\n        return 0.0\n    p = party.upper()\n    return max(fuzz.token_set_ratio(hint, p),\n               fuzz.token_set_ratio(hint, _vowel_drop(p)),\n               fuzz.partial_ratio(hint, p))\n\n\ndef _days(a: str, b: str) -> int:\n    return (date.fromisoformat(a) - date.fromisoformat(b)).days\n\n\ndef _date_ok(bank_date: str, ledger_date: str) -> bool:\n    d = _days(bank_date, ledger_date)\n    return -DATE_BEFORE <= d <= DATE_AFTER\n\n\ndef _date_ok_group(bank_date: str, ledger_date: str) -> bool:\n    d = _days(bank_date, ledger_date)\n    return -DATE_BEFORE <= d <= GROUP_AFTER\n\n\ndef _dir_ok(txn, entry) -> bool:\n    return (txn.direction == "credit") == (entry.entry_type == "receipt")\n\n\ndef flag_duplicates(txns):\n    """Same narration+ref+amount seen before -> later copies flagged."""\n    seen, dupes = {}, {}\n    for t in sorted(txns, key=lambda x: (x.date, x.txn_id)):\n        key = (t.narration, t.ref, round(t.amount, 2))\n        if key in seen:\n            dupes[t.txn_id] = seen[key]\n        else:\n            seen[key] = t.txn_id\n    return dupes  # dup_txn_id -> original_txn_id\n\n\ndef _greedy_assign(edges, bank_used, ledger_used):\n    """edges: list of (score_tuple, txn, entry, rule, explanation).\n    Higher score wins; each side used once. Deterministic tie-breaks."""\n    matches = []\n    for score, txn, entry, rule, expl in sorted(\n            edges, key=lambda e: (-e[0][0], e[0][1], e[1].txn_id, e[2].entry_id)):\n        if txn.txn_id in bank_used or entry.entry_id in ledger_used:\n            continue\n        bank_used.add(txn.txn_id)\n        ledger_used.add(entry.entry_id)\n        matches.append({"bank_ids": [txn.txn_id], "ledger_ids": [entry.entry_id],\n                        "rule": rule, "score": round(score[0], 1),\n                        "explanation": expl})\n    return matches\n\n\ndef reconcile(txns, entries):\n    bank_used, ledger_used = set(), set()\n    matches = []\n\n    dupes = flag_duplicates(txns)\n    live_txns = [t for t in txns if t.txn_id not in dupes]\n\n    # -------------------------------------------------- P1 exact amount\n    edges = []\n    for t in live_txns:\n        for e in entries:\n            if not _dir_ok(t, e) or abs(t.amount - e.amount) > 0.01:\n                continue\n            if not _date_ok(t.date, e.date):\n                continue\n            ns = name_score(t.narration, e.party)\n            gap = abs(_days(t.date, e.date))\n            edges.append(((ns + (7 - gap), gap), t, e, "P1_EXACT",\n                          f"exact amount {t.amount:,.2f}; name score {ns:.0f}; "\n                          f"date gap {gap}d"))\n    matches += _greedy_assign(edges, bank_used, ledger_used)\n\n    # -------------------------------------------------- P3 combined (N ledger -> 1 bank)\n    open_receipts = [e for e in entries\n                     if e.entry_id not in ledger_used and e.entry_type == "receipt"]\n    by_party = {}\n    for e in open_receipts:\n        by_party.setdefault(e.party, []).append(e)\n    for t in sorted(live_txns, key=lambda x: (x.date, x.txn_id)):\n        if t.txn_id in bank_used or t.direction != "credit":\n            continue\n        best = None\n        for party, group in sorted(by_party.items()):\n            cands = [e for e in group if e.entry_id not in ledger_used\n                     and _date_ok_group(t.date, e.date)\n                     and name_score(t.narration, party) >= NAME_THRESHOLD]\n            for r in (2, GROUP_MAX):\n                for combo in combinations(sorted(cands, key=lambda e: e.entry_id), r):\n                    if abs(sum(e.amount for e in combo) - t.amount) <= 0.01:\n                        best = combo\n                        break\n                if best:\n                    break\n            if best:\n                break\n        if best:\n            bank_used.add(t.txn_id)\n            for e in best:\n                ledger_used.add(e.entry_id)\n            invs = ", ".join(e.invoice_no or e.entry_id for e in best)\n            matches.append({"bank_ids": [t.txn_id],\n                            "ledger_ids": [e.entry_id for e in best],\n                            "rule": "P3_COMBINED", "score": 100.0,\n                            "explanation": f"one credit {t.amount:,.2f} settles "\n                                           f"{len(best)} invoices ({invs})"})\n\n    # -------------------------------------------------- P4 split (2 bank -> 1 ledger)\n    open_credits = [t for t in live_txns\n                    if t.txn_id not in bank_used and t.direction == "credit"]\n    for e in sorted(entries, key=lambda x: (x.date, x.entry_id)):\n        if e.entry_id in ledger_used or e.entry_type != "receipt":\n            continue\n        cands = [t for t in open_credits if t.txn_id not in bank_used\n                 and _date_ok_group(t.date, e.date)\n                 and name_score(t.narration, e.party) >= NAME_THRESHOLD]\n        found = None\n        for combo in combinations(sorted(cands, key=lambda t: t.txn_id), 2):\n            if abs(sum(t.amount for t in combo) - e.amount) <= 0.01:\n                found = combo\n                break\n        if found:\n            ledger_used.add(e.entry_id)\n            for t in found:\n                bank_used.add(t.txn_id)\n            matches.append({"bank_ids": [t.txn_id for t in found],\n                            "ledger_ids": [e.entry_id], "rule": "P4_SPLIT",\n                            "score": 100.0,\n                            "explanation": f"invoice {e.invoice_no or e.entry_id} "\n                                           f"({e.amount:,.2f}) paid in 2 parts"})\n\n    # -------------------------------------------------- P2 fee/short tolerance\n    edges = []\n    for t in live_txns:\n        if t.txn_id in bank_used:\n            continue\n        for e in entries:\n            if e.entry_id in ledger_used or not _dir_ok(t, e):\n                continue\n            delta = e.amount - t.amount\n            if delta <= 0.01 or delta > e.amount * TOL_PCT + TOL_ABS:\n                continue\n            if not _date_ok(t.date, e.date):\n                continue\n            ns = name_score(t.narration, e.party)\n            if ns < NAME_THRESHOLD:\n                continue\n            pct = delta / e.amount\n            kind = "gateway fee" if pct <= 0.025 else "short payment"\n            edges.append(((ns - pct * 100, abs(_days(t.date, e.date))), t, e,\n                          "P2_TOLERANCE",\n                          f"amount short by {delta:,.2f} ({pct:.2%}) — likely "\n                          f"{kind}; name score {ns:.0f}"))\n    matches += _greedy_assign(edges, bank_used, ledger_used)\n\n    # -------------------------------------------------- leftovers + near misses\n    unmatched_bank = []\n    for t in txns:\n        if t.txn_id in bank_used:\n            continue\n        if t.txn_id in dupes:\n            unmatched_bank.append({"bank_id": t.txn_id,\n                                   "suspect": "DUPLICATE",\n                                   "duplicate_of": dupes[t.txn_id]})\n            continue\n        near = sorted(\n            ({"entry_id": e.entry_id, "party": e.party,\n              "amount": e.amount, "delta": round(e.amount - t.amount, 2),\n              "name_score": round(name_score(t.narration, e.party), 0)}\n             for e in entries if e.entry_id not in ledger_used\n             and _dir_ok(t, e) and _date_ok(t.date, e.date)),\n            key=lambda c: (abs(c["delta"]), -c["name_score"]))[:3]\n        unmatched_bank.append({"bank_id": t.txn_id, "suspect": None,\n                               "near_misses": near})\n\n    unmatched_ledger = [{"ledger_id": e.entry_id}\n                        for e in entries if e.entry_id not in ledger_used]\n\n    return {"matches": matches, "unmatched_bank": unmatched_bank,\n            "unmatched_ledger": unmatched_ledger}\n'

FILES['milaan/evalx/__init__.py'] = ''

FILES['milaan/evalx/harness.py'] = '"""Eval harness: matching output vs planted ground truth.\n\nPair-level metrics: each match group expands to (bank_id, ledger_id) pairs.\n  precision = correct predicted pairs / all predicted pairs\n  recall    = correct predicted pairs / all truth pairs\nPlus: duplicate-detection accuracy and unmatched-set overlap.\n"""\n\nimport json\nfrom pathlib import Path\n\n\ndef _pairs(match_list):\n    pairs = set()\n    for m in match_list:\n        for b in m["bank_ids"]:\n            for l in m["ledger_ids"]:\n                pairs.add((b, l))\n    return pairs\n\n\ndef evaluate_month(result: dict, gt: dict) -> dict:\n    pred = _pairs(result["matches"])\n    truth = _pairs(gt["matches"])\n    tp = len(pred & truth)\n    precision = tp / len(pred) if pred else 1.0\n    recall = tp / len(truth) if truth else 1.0\n    f1 = (2 * precision * recall / (precision + recall)\n          if precision + recall else 0.0)\n\n    truth_dupes = {u["bank_id"] for u in gt["unmatched_bank"]\n                   if u["reason"] == "DUPLICATE_BANK"}\n    pred_dupes = {u["bank_id"] for u in result["unmatched_bank"]\n                  if u.get("suspect") == "DUPLICATE"}\n\n    truth_ub = {u["bank_id"] for u in gt["unmatched_bank"]}\n    pred_ub = {u["bank_id"] for u in result["unmatched_bank"]}\n    truth_ul = {u["ledger_id"] for u in gt["unmatched_ledger"]}\n    pred_ul = {u["ledger_id"] for u in result["unmatched_ledger"]}\n\n    return {\n        "pairs_pred": len(pred), "pairs_truth": len(truth), "pairs_correct": tp,\n        "precision": round(precision, 4), "recall": round(recall, 4),\n        "f1": round(f1, 4),\n        "dupes_caught": len(pred_dupes & truth_dupes),\n        "dupes_truth": len(truth_dupes),\n        "false_unmatched_bank": len(pred_ub - truth_ub),\n        "missed_unmatched_bank": len(truth_ub - pred_ub),\n        "false_unmatched_ledger": len(pred_ul - truth_ul),\n        "missed_unmatched_ledger": len(truth_ul - pred_ul),\n        "wrong_pairs": sorted(pred - truth)[:10],\n        "missed_pairs": sorted(truth - pred)[:10],\n    }\n\n\ndef evaluate_dir(synth_root: str, reconcile_fn, parse_statement, parse_ledger,\n                 months=None):\n    root = Path(synth_root)\n    rows, agg = [], {"pred": 0, "truth": 0, "tp": 0}\n    for mdir in sorted(root.iterdir()):\n        if not mdir.is_dir():\n            continue\n        if months and mdir.name not in months:\n            continue\n        stmt = next(mdir.glob("statement_*.csv"))\n        txns, _, _ = parse_statement(str(stmt))\n        entries = parse_ledger(str(mdir / "ledger.csv"))\n        gt = json.loads((mdir / "ground_truth.json").read_text(encoding="utf-8"))\n        res = reconcile_fn(txns, entries)\n        m = evaluate_month(res, gt)\n        m["month"] = mdir.name\n        rows.append(m)\n        agg["pred"] += m["pairs_pred"]\n        agg["truth"] += m["pairs_truth"]\n        agg["tp"] += m["pairs_correct"]\n    p = agg["tp"] / agg["pred"] if agg["pred"] else 1.0\n    r = agg["tp"] / agg["truth"] if agg["truth"] else 1.0\n    overall = {"precision": round(p, 4), "recall": round(r, 4),\n               "f1": round(2 * p * r / (p + r), 4) if p + r else 0.0}\n    return rows, overall\n'

FILES['milaan/report/__init__.py'] = ''

FILES['milaan/report/excel.py'] = '"""Excel exception report — the deliverable an accountant actually opens.\n\nSheets:\n  Summary          — counts, match rate, what needs attention\n  Matched          — full audit trail (rule, score, explanation)\n  Unmatched Bank   — bank lines needing review, with near-miss candidates\n  Unmatched Ledger — ledger entries with no bank movement\n"""\n\nfrom openpyxl import Workbook\nfrom openpyxl.styles import Font, PatternFill, Alignment\n\nHDR = Font(bold=True, color="FFFFFF")\nFILL = PatternFill("solid", fgColor="0B5D3B")\nWARN = PatternFill("solid", fgColor="FFF3CD")\n\n\ndef _sheet(wb, title, headers, widths):\n    ws = wb.create_sheet(title)\n    ws.append(headers)\n    for c, w in enumerate(widths, 1):\n        ws.cell(1, c).font = HDR\n        ws.cell(1, c).fill = FILL\n        ws.column_dimensions[ws.cell(1, c).column_letter].width = w\n    ws.freeze_panes = "A2"\n    return ws\n\n\ndef write_report(path, result, txns, entries, meta=None):\n    tmap = {t.txn_id: t for t in txns}\n    emap = {e.entry_id: e for e in entries}\n    wb = Workbook()\n    wb.remove(wb.active)\n\n    # ---------------- Summary\n    ws = _sheet(wb, "Summary", ["Item", "Value"], [42, 24])\n    n_bank, n_ledger = len(txns), len(entries)\n    n_matched_bank = sum(len(m["bank_ids"]) for m in result["matches"])\n    n_matched_ledger = sum(len(m["ledger_ids"]) for m in result["matches"])\n    dupes = [u for u in result["unmatched_bank"] if u.get("suspect") == "DUPLICATE"]\n    rows = [\n        ("Bank transactions", n_bank),\n        ("Ledger entries", n_ledger),\n        ("Bank txns matched", f"{n_matched_bank} ({n_matched_bank/n_bank:.1%})"),\n        ("Ledger entries matched", f"{n_matched_ledger} ({n_matched_ledger/max(n_ledger,1):.1%})"),\n        ("Suspected duplicate bank lines", len(dupes)),\n        ("Bank lines needing review", len(result["unmatched_bank"]) - len(dupes)),\n        ("Ledger entries with no bank movement", len(result["unmatched_ledger"])),\n    ]\n    if meta:\n        rows = list(meta.items()) + rows\n    for r in rows:\n        ws.append(list(r))\n\n    # ---------------- Matched (audit trail)\n    ws = _sheet(wb, "Matched",\n                ["Rule", "Bank txn(s)", "Bank date", "Bank amount",\n                 "Ledger entry(ies)", "Party", "Ledger amount", "Explanation"],\n                [14, 16, 12, 14, 18, 22, 14, 60])\n    for m in sorted(result["matches"], key=lambda x: x["bank_ids"][0]):\n        bts = [tmap[b] for b in m["bank_ids"]]\n        les = [emap[l] for l in m["ledger_ids"]]\n        ws.append([m["rule"],\n                   ", ".join(m["bank_ids"]), bts[0].date,\n                   sum(t.amount for t in bts),\n                   ", ".join(m["ledger_ids"]), les[0].party,\n                   sum(e.amount for e in les), m["explanation"]])\n        if m["rule"] != "P1_EXACT":\n            for c in range(1, 9):\n                ws.cell(ws.max_row, c).fill = WARN\n\n    # ---------------- Unmatched Bank\n    ws = _sheet(wb, "Unmatched Bank",\n                ["Bank txn", "Date", "Direction", "Amount", "Narration",\n                 "Suspect", "Nearest candidates (entry / party / delta / name score)"],\n                [10, 12, 10, 14, 46, 22, 64])\n    for u in result["unmatched_bank"]:\n        t = tmap[u["bank_id"]]\n        if u.get("suspect") == "DUPLICATE":\n            suspect = f"DUPLICATE of {u[\'duplicate_of\']}"\n            near = ""\n        else:\n            suspect = ""\n            near = " | ".join(\n                f"{c[\'entry_id\']} {c[\'party\']} Δ{c[\'delta\']:,.2f} ns{c[\'name_score\']:.0f}"\n                for c in u.get("near_misses", []))\n        ws.append([t.txn_id, t.date, t.direction, t.amount,\n                   t.narration, suspect, near])\n\n    # ---------------- Unmatched Ledger\n    ws = _sheet(wb, "Unmatched Ledger",\n                ["Entry", "Date", "Party", "Description", "Invoice",\n                 "Amount", "Type"],\n                [10, 12, 22, 30, 12, 14, 10])\n    for u in result["unmatched_ledger"]:\n        e = emap[u["ledger_id"]]\n        ws.append([e.entry_id, e.date, e.party, e.description,\n                   e.invoice_no, e.amount, e.entry_type])\n\n    for ws in wb.worksheets:\n        for row in ws.iter_rows(min_row=2):\n            for cell in row:\n                cell.alignment = Alignment(vertical="top", wrap_text=(cell.column in (5, 7, 8)))\n    wb.save(path)\n    return path\n'

FILES['cli.py'] = '"""MilaanAI CLI (Week 1).\n\n  python cli.py generate --months 10 --out data/synth --seed 42\n  python cli.py ingest --statement data/synth/m01/statement_hdfc.csv --ledger data/synth/m01/ledger.csv\n"""\n\nimport argparse\nimport json\nfrom pathlib import Path\n\nfrom milaan.generator.generate import generate_month, write_month\nfrom milaan.ingest.adapters import parse_statement, parse_ledger\nfrom milaan.ingest.integrity import check_balance\n\nFORMATS = ["hdfc", "icici", "sbi"]\n\n\ndef cmd_generate(args):\n    out_root = Path(args.out)\n    for i in range(args.months):\n        seed = args.seed + i\n        month = (i % 12) + 1\n        bank, ledger, gt = generate_month(seed, 2026, month)\n        fmt = FORMATS[i % 3]\n        mdir = out_root / f"m{i+1:02d}"\n        write_month(str(mdir), fmt, bank, ledger, gt)\n        n_disc = len(gt["unmatched_bank"]) + len(gt["unmatched_ledger"]) + sum(\n            1 for m in gt["matches"] if m["type"] != "CLEAN")\n        print(f"m{i+1:02d} [{fmt.upper():5}] bank={len(bank):3} "\n              f"ledger={len(ledger):3} planted_discrepancies={n_disc}")\n    print(f"\\nDone -> {out_root}  (last {args.holdout} months are HOLDOUT — "\n          "do not tune against them)")\n\n\ndef cmd_ingest(args):\n    txns, opening, fmt = parse_statement(args.statement)\n    report = check_balance(txns, opening)\n    print(f"Format detected : {fmt.upper()}")\n    print(f"Transactions    : {report[\'n_txns\']}")\n    print(f"Opening balance : {report[\'opening\']:,.2f}")\n    print(f"Closing balance : {report[\'closing\']:,.2f}")\n    print("Balance check   : PASSED")\n    if args.ledger:\n        entries = parse_ledger(args.ledger)\n        print(f"Ledger entries  : {len(entries)}")\n    print("\\nFirst 5 normalized txns:")\n    for t in txns[:5]:\n        print(f"  {t.txn_id} {t.date} {t.direction:6} {t.amount:>12,.2f}  "\n              f"{t.narration[:48]}")\n\n\n\n\ndef cmd_reconcile(args):\n    import json as _json\n    from milaan.match.engine import reconcile as _rec\n    from milaan.report.excel import write_report\n    txns, opening, fmt = parse_statement(args.statement)\n    check_balance(txns, opening)\n    entries = parse_ledger(args.ledger)\n    result = _rec(txns, entries)\n    out = Path(args.out)\n    out.parent.mkdir(parents=True, exist_ok=True)\n    n_bank = len(txns)\n    n_matched = sum(len(m["bank_ids"]) for m in result["matches"])\n    write_report(str(out), result, txns, entries,\n                 meta={"Statement": args.statement, "Format": fmt.upper()})\n    (out.with_suffix(".json")).write_text(\n        _json.dumps(result, indent=2, ensure_ascii=False), encoding="utf-8")\n    print(f"Matched {n_matched}/{n_bank} bank txns "\n          f"({n_matched/n_bank:.1%}) via {len(result[\'matches\'])} match groups")\n    print(f"Needs review: {len(result[\'unmatched_bank\'])} bank, "\n          f"{len(result[\'unmatched_ledger\'])} ledger")\n    print(f"Report -> {out}")\n\n\ndef cmd_eval(args):\n    from milaan.match.engine import reconcile as _rec\n    from milaan.evalx.harness import evaluate_dir\n    months = set(args.months.split(",")) if args.months else None\n    rows, overall = evaluate_dir(args.dir, _rec, parse_statement, parse_ledger,\n                                 months=months)\n    for r in rows:\n        print(f"{r[\'month\']}: P={r[\'precision\']:.3f} R={r[\'recall\']:.3f} "\n              f"F1={r[\'f1\']:.3f} dupes {r[\'dupes_caught\']}/{r[\'dupes_truth\']}")\n        for w in r["wrong_pairs"]:\n            print(f"   WRONG {w}")\n        for w in r["missed_pairs"]:\n            print(f"   MISSED {w}")\n    print(f"OVERALL: P={overall[\'precision\']:.4f} R={overall[\'recall\']:.4f} "\n          f"F1={overall[\'f1\']:.4f}")\n\ndef main():\n    p = argparse.ArgumentParser(prog="milaan")\n    sub = p.add_subparsers(dest="cmd", required=True)\n\n    g = sub.add_parser("generate")\n    g.add_argument("--months", type=int, default=10)\n    g.add_argument("--out", default="data/synth")\n    g.add_argument("--seed", type=int, default=42)\n    g.add_argument("--holdout", type=int, default=3)\n    g.set_defaults(func=cmd_generate)\n\n    i = sub.add_parser("ingest")\n    i.add_argument("--statement", required=True)\n    i.add_argument("--ledger")\n    i.set_defaults(func=cmd_ingest)\n\n    r = sub.add_parser("reconcile")\n    r.add_argument("--statement", required=True)\n    r.add_argument("--ledger", required=True)\n    r.add_argument("--out", default="outputs/reconciliation_report.xlsx")\n    r.set_defaults(func=cmd_reconcile)\n\n    e = sub.add_parser("eval")\n    e.add_argument("--dir", default="data/synth")\n    e.add_argument("--months", help="comma-separated, e.g. m08,m09,m10")\n    e.set_defaults(func=cmd_eval)\n\n    args = p.parse_args()\n    args.func(args)\n\n\nif __name__ == "__main__":\n    main()\n'

FILES['tests/test_week2.py'] = '"""Week 2 tests — matching engine, eval harness, Excel report. No keys."""\n\nimport json\n\nfrom milaan.generator.generate import generate_month, write_month\nfrom milaan.ingest.adapters import parse_statement, parse_ledger\nfrom milaan.match.engine import (reconcile, name_score, narration_hint,\n                                 flag_duplicates)\nfrom milaan.evalx.harness import evaluate_month\nfrom milaan.report.excel import write_report\n\n\ndef _run(seed=101, fmt="hdfc", tmp_path=None):\n    bank, ledger, gt = generate_month(seed=seed, year=2026, month=3)\n    if tmp_path:\n        write_month(str(tmp_path), fmt, bank, ledger, gt)\n        txns, _, _ = parse_statement(str(tmp_path / f"statement_{fmt}.csv"))\n        entries = parse_ledger(str(tmp_path / "ledger.csv"))\n        return txns, entries, gt\n    return bank, ledger, gt\n\n\n# ------------------------------------------------------------ narration/name\ndef test_narration_hint_strips_noise():\n    h = narration_hint("UPI-SHRM TRDRS-sharma4@okicici-428730877482-PAYMENT")\n    assert h == "SHRM TRDRS"\n\n\ndef test_name_score_handles_vowel_drop():\n    assert name_score("IMPS-371052246567-SHRMA TRDRS", "Sharma Traders") >= 85\n\n\ndef test_name_score_rejects_wrong_party():\n    assert name_score("NEFT CR-N12345678-BALAJI PACKAGING", "Sharma Traders") < 70\n\n\n# ------------------------------------------------------------ duplicates\ndef test_flag_duplicates():\n    bank, _, gt = _run(seed=205)\n    dupes = flag_duplicates(bank)\n    truth = {u["bank_id"] for u in gt["unmatched_bank"]\n             if u["reason"] == "DUPLICATE_BANK"}\n    assert truth <= (set(dupes.keys()) | set())  # every planted dupe flagged\n\n\n# ------------------------------------------------------------ engine quality\ndef test_engine_meets_bar_on_fresh_seeds(tmp_path):\n    """Seeds never used during tuning; PRD bar: P>=0.98, R>=0.90."""\n    agg = {"pred": 0, "truth": 0, "tp": 0}\n    for i, seed in enumerate([911, 912, 913]):\n        d = tmp_path / str(seed)\n        d.mkdir()\n        txns, entries, gt = _run(seed=seed, fmt=["hdfc", "icici", "sbi"][i],\n                                 tmp_path=d)\n        res = reconcile(txns, entries)\n        m = evaluate_month(res, gt)\n        agg["pred"] += m["pairs_pred"]\n        agg["truth"] += m["pairs_truth"]\n        agg["tp"] += m["pairs_correct"]\n    precision = agg["tp"] / agg["pred"]\n    recall = agg["tp"] / agg["truth"]\n    assert precision >= 0.98, f"precision {precision:.3f} below bar"\n    assert recall >= 0.90, f"recall {recall:.3f} below bar"\n\n\ndef test_engine_deterministic():\n    bank, ledger, _ = _run(seed=77)\n    a = reconcile(bank, ledger)\n    b = reconcile(bank, ledger)\n    assert json.dumps(a, sort_keys=True) == json.dumps(b, sort_keys=True)\n\n\ndef test_every_match_has_audit_trail():\n    bank, ledger, _ = _run(seed=88)\n    res = reconcile(bank, ledger)\n    for m in res["matches"]:\n        assert m["rule"] in {"P1_EXACT", "P2_TOLERANCE", "P3_COMBINED", "P4_SPLIT"}\n        assert m["explanation"]\n\n\ndef test_no_double_assignment():\n    bank, ledger, _ = _run(seed=99)\n    res = reconcile(bank, ledger)\n    bank_ids, ledger_ids = [], []\n    for m in res["matches"]:\n        bank_ids += m["bank_ids"]\n        ledger_ids += m["ledger_ids"]\n    bank_ids += [u["bank_id"] for u in res["unmatched_bank"]]\n    ledger_ids += [u["ledger_id"] for u in res["unmatched_ledger"]]\n    assert sorted(bank_ids) == sorted(t.txn_id for t in bank)\n    assert sorted(ledger_ids) == sorted(e.entry_id for e in ledger)\n\n\n# ------------------------------------------------------------ report\ndef test_excel_report_writes(tmp_path):\n    txns, entries, _ = _run(seed=55, fmt="sbi", tmp_path=tmp_path)\n    res = reconcile(txns, entries)\n    out = tmp_path / "report.xlsx"\n    write_report(str(out), res, txns, entries, meta={"Client": "Test & Co"})\n    assert out.exists() and out.stat().st_size > 5000\n    from openpyxl import load_workbook\n    wb = load_workbook(out)\n    assert set(wb.sheetnames) == {"Summary", "Matched", "Unmatched Bank",\n                                  "Unmatched Ledger"}\n'


def main():
    for rel, content in FILES.items():
        path = os.path.join(os.getcwd(), rel.replace("/", os.sep))
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        with open(path, "w", encoding="utf-8", newline="\n") as fh:
            fh.write(content)
        print(f"  wrote: {rel}")
    print("""
Week 2 installed.
NEXT STEPS
  1. python -m pytest                     (expect 22 passed)
  2. python cli.py generate --months 10 --out data/synth      (regenerate — ID fix)
  3. python cli.py reconcile --statement data/synth/m01/statement_hdfc.csv --ledger data/synth/m01/ledger.csv --out outputs/m01_report.xlsx
  4. Open outputs/m01_report.xlsx in Excel
  5. python cli.py eval --months m08,m09,m10                  (holdout metrics)
""")


if __name__ == "__main__":
    main()
